const raw = items[0]?.json || {};
const payload = raw.payload && typeof raw.payload === 'object' && !Array.isArray(raw.payload) ? raw.payload : raw;
const workflowSource = payload.workflow_source || payload.workflowSource || raw.workflow_source || raw.workflowSource;
const subject = payload.subject || raw.subject;
const summary = payload.summary || raw.summary;
if (!workflowSource) throw new Error('Missing workflow_source / workflowSource');
if (!subject) throw new Error('Missing subject');
if (!summary) throw new Error('Missing summary');
return [{
  json: {
    meta: {
      workflow_name: 'Owner_Notification',
      timestamp: new Date().toISOString(),
      trigger_source: raw.trigger_source || 'owner_notification_webhook',
      risk_level: raw.risk_level || 'high'
    },
    context: {
      canonical_links: [
        '[[08-Runbooks/System/Escalation-Matrix|Escalation Matrix]]'
      ],
      constraints: [
        'Owner notifications should be reserved for true gated or high-risk events'
      ]
    },
    payload: {
      workflow_source: String(workflowSource),
      severity: String(payload.severity || raw.severity || 'high'),
      subject: String(subject),
      summary: String(summary),
      details: Array.isArray(payload.details) ? payload.details.map(String) : Array.isArray(raw.details) ? raw.details.map(String) : [],
      next_step: String(payload.next_step || payload.nextStep || raw.next_step || raw.nextStep || ''),
      links: Array.isArray(payload.links) ? payload.links.map(String) : Array.isArray(raw.links) ? raw.links.map(String) : [],
      recipient: String(payload.recipient || raw.recipient || $env.VURIUM_OWNER_EMAIL || '')
    }
  }
}];

const item = items[0]?.json || {};
const required = ['agent', 'workflow', 'status', 'channel', 'workflow_source', 'severity', 'recipient', 'subject', 'reason', 'next_step'];
for (const key of required) {
  if (!(key in item)) throw new Error(`Missing required key: ${key}`);
}
const allowedStatus = new Set(['done', 'partial', 'blocked', 'needs_review', 'queued']);
if (!allowedStatus.has(item.status)) throw new Error(`Invalid status: ${item.status}`);
const allowedSeverity = new Set(['low', 'medium', 'high', 'critical']);
if (!allowedSeverity.has(item.severity)) throw new Error(`Invalid severity: ${item.severity}`);
item.execution_summary = item.status === 'done'
  ? `Owner notification sent to ${item.recipient}`
  : `Owner notification requires manual follow-up: ${item.reason}`;
return [{ json: item }];
